package srp

import (
	"encoding/hex"
	"math/big"
	"testing"
)

// Vectors generated by `node test/srp.selftest.mjs --vectors` — they prove the Go
// server and the browser client (web/js/srp.js) speak the identical protocol.
const (
	vUsername = "alice"
	vPassword = "correct horse battery staple"
	vSaltHex  = "000102030405060708090a0b0c0d0e0f"
	vAHex     = ""
	vBHex     = ""
	vBbHex    = "6465666768696a6b6c6d6e6f707172737475767778797a7b7c7d7e7f80818283"
	vVHex     = ""
	vM1Hex    = "3f6ccdd2c124701cc312ac8a728d0e7afc31804bd27bfcc1ba91a4b5d184f7ea"
	vM2Hex    = "19824f6ec5869917f2d6381c137785ef14e5e8bc78bcb55970fae31848cdf373"
	vKHex     = "3fde1f8980f5a38d5a67113dd223e748131b7d9186c8ad7d0b79879f1bc26d86"
)

func TestCrossImplVectors(t *testing.T) {
	salt := mustBytes(t, vSaltHex)

	// Verifier must match the browser's.
	v := Verifier(vUsername, vPassword, salt)
	if got := v.Text(16); got != trimLead(vVHex) {
		t.Fatalf("verifier mismatch with JS client")
	}

	// Server B from the fixed b must match the browser's view.
	b := mustBig(t, vBbHex)
	B := new(big.Int).Mod(new(big.Int).Add(new(big.Int).Mul(k, v), new(big.Int).Exp(g, b, N)), N)
	if B.Text(16) != trimLead(vBHex) {
		t.Fatalf("server B mismatch with JS client")
	}

	// The decisive interop check: feed the JS client's A and M1 to the Go server.
	c := &Challenge{b: b, Bpub: B, v: v}
	A := mustBig(t, vAHex)
	M2, K, err := c.Verify(A, mustBytes(t, vM1Hex))
	if err != nil {
		t.Fatalf("Go server rejected JS client proof: %v", err)
	}
	if hex.EncodeToString(M2) != vM2Hex {
		t.Errorf("M2 mismatch: server and JS client disagree")
	}
	if hex.EncodeToString(K) != vKHex {
		t.Errorf("session key K mismatch between server and JS client")
	}
}

func TestGoRoundTrip(t *testing.T) {
	username, password := "bob", "hunter2-hunter2"
	salt := []byte("sixteen-byte-slt")
	v := Verifier(username, password, salt)

	c, err := NewChallenge(v)
	if err != nil {
		t.Fatal(err)
	}
	A, M1, expectM2, clientK := clientProof(t, username, password, salt, c.Bpub)
	M2, K, err := c.Verify(A, M1)
	if err != nil {
		t.Fatalf("server rejected honest client: %v", err)
	}
	if hex.EncodeToString(M2) != hex.EncodeToString(expectM2) {
		t.Error("client could not authenticate server (M2)")
	}
	if hex.EncodeToString(K) != hex.EncodeToString(clientK) {
		t.Error("session keys differ")
	}
}

func TestRejectsWrongPassword(t *testing.T) {
	v := Verifier("bob", "right-password", []byte("sixteen-byte-slt"))
	c, _ := NewChallenge(v)
	A, M1, _, _ := clientProof(t, "bob", "WRONG-password", []byte("sixteen-byte-slt"), c.Bpub)
	if _, _, err := c.Verify(A, M1); err != ErrProof {
		t.Fatalf("expected ErrProof for wrong password, got %v", err)
	}
}

func TestRejectsAZeroModN(t *testing.T) {
	v := Verifier("bob", "pw", []byte("sixteen-byte-slt"))
	c, _ := NewChallenge(v)
	if _, _, err := c.Verify(N, make([]byte, 32)); err != ErrBadParam { // A = N ≡ 0
		t.Fatalf("expected ErrBadParam for A ≡ 0, got %v", err)
	}
}

// clientProof mirrors web/js/srp.js for the Go-only round-trip tests.
func clientProof(t *testing.T, username, password string, salt []byte, B *big.Int) (A *big.Int, M1, M2, K []byte) {
	t.Helper()
	a, err := randInt()
	if err != nil {
		t.Fatal(err)
	}
	A = new(big.Int).Exp(g, a, N)
	x := computeX(salt, username, password)
	u := hashInt(pad(A), pad(B))
	// base = (B - k*g^x) mod N
	base := new(big.Int).Mod(new(big.Int).Sub(B, new(big.Int).Mul(k, new(big.Int).Exp(g, x, N))), N)
	S := new(big.Int).Exp(base, new(big.Int).Add(a, new(big.Int).Mul(u, x)), N)
	Sp := pad(S)
	M1 = hashBytes(pad(A), pad(B), Sp)
	M2 = hashBytes(pad(A), M1, Sp)
	K = hashBytes(Sp)
	return A, M1, M2, K
}

func mustBytes(t *testing.T, h string) []byte {
	t.Helper()
	b, err := hex.DecodeString(h)
	if err != nil {
		t.Fatalf("bad hex: %v", err)
	}
	return b
}

func mustBig(t *testing.T, h string) *big.Int {
	t.Helper()
	n, ok := new(big.Int).SetString(h, 16)
	if !ok {
		t.Fatalf("bad big hex")
	}
	return n
}

func trimLead(h string) string {
	for len(h) > 1 && h[0] == '0' {
		h = h[1:]
	}
	return h
}
